PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "two_factor_secret" text, "two_factor_recovery_codes" text, "two_factor_confirmed_at" datetime, "role" varchar not null default 'user', "status" varchar not null default 'pending', "phone" varchar, "google_id" varchar);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "documents" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "file_path" varchar not null, "category" varchar, "size" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "career_jobs" ("id" integer primary key autoincrement not null, "title" varchar not null, "type" varchar not null, "location" varchar not null, "description" text not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "leads" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "phone" varchar not null, "subject" varchar, "message" text not null, "is_read" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "posts" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "content" text not null, "excerpt" varchar, "featured_image" varchar, "status" varchar check ("status" in ('draft', 'published')) not null default 'draft', "author_id" integer not null, "published_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("author_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "testimonials" ("id" integer primary key autoincrement not null, "client_name" varchar not null, "business_name" varchar, "content" text not null, "rating" integer not null default '5', "avatar" varchar, "is_featured" tinyint(1) not null default '0', "status" varchar not null default 'published', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "ticket_replies" ("id" integer primary key autoincrement not null, "ticket_id" integer not null, "user_id" integer not null, "message" text not null, "created_at" datetime, "updated_at" datetime, foreign key("ticket_id") references "tickets"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "tickets" ("id" integer primary key autoincrement not null, "user_id" integer not null, "subject" varchar not null, "description" text not null, "status" varchar not null default 'open', "priority" varchar not null default 'medium', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "posts_slug_unique" on "posts" ("slug");
COMMIT;
